import{_ as p,c as t}from"./app.90a21e26.js";const o={},n=t('<h1 id="_36-\u8BB2-\u6D45\u8C08\u6D4B\u8BD5\u6570\u636E\u7684\u75DB\u70B9" tabindex="-1"><a class="header-anchor" href="#_36-\u8BB2-\u6D45\u8C08\u6D4B\u8BD5\u6570\u636E\u7684\u75DB\u70B9" aria-hidden="true">#</a> 36 \u8BB2\uFF1A\u6D45\u8C08\u6D4B\u8BD5\u6570\u636E\u7684\u75DB\u70B9</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\u3002\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\uFF1A\u6D45\u8C08\u6D4B\u8BD5\u6570\u636E\u7684\u75DB\u70B9\u3002</p><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u548C\u4F60\u5206\u4EAB\u4E86\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u7684\u56DB\u5927\u7C7B\u65B9\u6CD5\uFF0C\u5373\u57FA\u4E8E GUI \u64CD\u4F5C\u751F\u6210\u6D4B\u8BD5\u6570\u636E\u3001\u901A\u8FC7 API \u8C03\u7528\u751F\u6210\u6D4B\u8BD5\u6570\u636E\u3001\u901A\u8FC7\u6570\u636E\u5E93\u64CD\u4F5C\u751F\u6210\u6D4B\u8BD5\u6570\u636E\uFF0C\u4EE5\u53CA\u7EFC\u5408\u8FD0\u7528 API \u548C\u6570\u636E\u5E93\u7684\u65B9\u5F0F\u751F\u6210\u6D4B\u8BD5\u6570\u636E\u3002</p><p>\u4F46\u662F\uFF0C\u6211\u5E76\u6CA1\u6709\u8C08\u5230\u5E94\u8BE5\u5728\u4EC0\u4E48\u65F6\u673A\u521B\u5EFA\u8FD9\u4E9B\u6D4B\u8BD5\u6570\u636E\u3002\u6BD4\u5982\uFF0C\u662F\u5728\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u5B9E\u65F6\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u8FD8\u662F\u5728\u51C6\u5907\u6D4B\u8BD5\u73AF\u5883\u65F6\u4E00\u4E0B\u5B50\u51C6\u5907\u597D\u6240\u6709\u7684\u6D4B\u8BD5\u6570\u636E\u5462\u3002</p><p>\u5176\u5B9E\uFF0C\u5728\u4E0D\u540C\u7684\u65F6\u673A\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u5C31\u662F\u4E3A\u4E86\u89E3\u51B3\u51C6\u5907\u6D4B\u8BD5\u6570\u636E\u7684\u4E0D\u540C\u75DB\u70B9\u3002\u90A3\u4E48\uFF0C\u51C6\u5907\u6D4B\u8BD5\u6570\u636E\u7684\u75DB\u70B9\uFF0C\u90FD\u4F53\u73B0\u5728\u54EA\u4E9B\u65B9\u9762\u5462\uFF1F</p><ul><li>\u5728\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u8FC7\u7A0B\u4E2D\uFF0C\u521B\u5EFA\u6240\u9700\u7684\u6570\u636E\u5F80\u5F80\u4F1A\u8017\u65F6\u8F83\u957F\uFF0C\u4ECE\u800C\u4F7F\u5F97\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7684\u65F6\u95F4\u53D8\u957F\uFF1B</li><li>\u5728\u6D4B\u8BD5\u6267\u884C\u4E4B\u524D\uFF0C\u5148\u6279\u91CF\u751F\u6210\u6240\u6709\u9700\u8981\u7528\u5230\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u5C31\u6709\u53EF\u80FD\u51FA\u73B0\u5728\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u65F6\uFF0C\u8FD9\u4E9B\u4E8B\u5148\u521B\u5EFA\u597D\u7684\u6570\u636E\u5DF2\u7ECF\u88AB\u4FEE\u6539\u800C\u65E0\u6CD5\u6B63\u5E38\u4F7F\u7528\u4E86\u7684\u60C5\u51B5\uFF1B</li><li>\u5728\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u6D4B\u8BD5\u73AF\u5883\u672C\u8EAB\u7684\u4E0D\u7A33\u5B9A\uFF0C\u4E5F\u4F1A\u963B\u788D\u6D4B\u8BD5\u6570\u636E\u7684\u987A\u5229\u521B\u5EFA\u3002 \u90A3\u4E48\uFF0C\u4ECA\u5929\u6211\u4EEC\u5C31\u5148\u6765\u804A\u804A\u4E0E\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u65F6\u673A\u76F8\u5173\u7684\u8BDD\u9898\u3002</li></ul><p>\u4ECE\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u7684\u65F6\u673A\u6765\u770B\uFF0C\u4E3B\u8981\u5206\u4E3A On-the-fly\uFF08\u5B9E\u65F6\u521B\u5EFA\uFF09\u548C Out-of-box\uFF08\u4E8B\u5148\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF09\u4E24\u7C7B\u65B9\u6CD5\u3002\u8FD9\u4E24\u7C7B\u65B9\u6CD5\u90FD\u6709\u5404\u81EA\u7684\u4F18\u7F3A\u70B9\uFF0C\u4EE5\u53CA\u9002\u7528\u7684\u6700\u4F73\u573A\u666F\u3002\u800C\u4E14\u5728\u5DE5\u7A0B\u5B9E\u8DF5\u4E2D\uFF0C\u6211\u4EEC\u5F80\u5F80\u4F1A\u7EFC\u5408\u4F7F\u7528\u8FD9\u4E24\u79CD\u65B9\u6CD5\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5148\u548C\u4F60\u5206\u522B\u4ECB\u7ECD\u4E00\u4E0B\u8FD9\u4E24\u7C7B\u65B9\u6CD5\u3002\u5176\u5B9E\uFF0C\u8FD9\u4E24\u7C7B\u65B9\u6CD5\u6211\u5DF2\u7ECF\u5728\u7B2C 15 \u7BC7\u6587\u7AE0\u300A\u8FC7\u4E0D\u4E86\u7684\u574E\uFF1A\u804A\u804A GUI \u81EA\u52A8\u5316\u8FC7\u7A0B\u4E2D\u7684\u6D4B\u8BD5\u6570\u636E\u300B\u4E2D\u63D0\u5230\u8FC7\u4E86\u3002\u4F46\u662F\uFF0C\u5F53\u65F6\u6211\u53EA\u662F\u7B3C\u7EDF\u5730\u548C\u4F60\u5206\u4EAB\u4E86\u8FD9\u4E24\u7C7B\u65B9\u6CD5\u7684\u6982\u5FF5\uFF0C\u5E76\u6CA1\u6709\u8BE6\u7EC6\u5C55\u5F00\u8BA8\u8BBA\u3002\u6240\u4EE5\uFF0C\u6211\u4ECA\u5929\u5C31\u4F1A\u901A\u8FC7\u4E00\u4E9B\u5B9E\u4F8B\uFF0C\u548C\u4F60\u66F4\u52A0\u8BE6\u7EC6\u5730\u8BA8\u8BBA\u8FD9\u4E24\u7C7B\u65B9\u6CD5\u3002</p><p><strong>On-the-fly</strong></p><p>On-the-fly \u65B9\u6CD5\uFF0C\u53C8\u79F0\u5B9E\u65F6\u521B\u5EFA\u65B9\u6CD5\uFF0C\u6307\u7684\u662F\u5728\u6D4B\u8BD5\u7528\u4F8B\u7684\u4EE3\u7801\u4E2D\u5B9E\u65F6\u521B\u5EFA\u8981\u4F7F\u7528\u5230\u7684\u6D4B\u8BD5\u6570\u636E\u3002\u6BD4\u5982\uFF0C\u5BF9\u4E8E\u7528\u6237\u767B\u5F55\u529F\u80FD\u7684\u6D4B\u8BD5\uFF0C\u90A3\u4E48\u5728\u6D4B\u8BD5\u7528\u4F8B\u5F00\u59CB\u7684\u90E8\u5206\uFF0C\u9996\u5148\u8C03\u7528\u6211\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\u4ECB\u7ECD\u7684\u521B\u5EFA\u65B0\u7528\u6237\u7684\u6570\u636E\u51C6\u5907\u51FD\u6570\u6765\u751F\u6210\u4E00\u4E2A\u65B0\u7528\u6237\uFF0C\u63A5\u4E0B\u6765\u7684\u6D4B\u8BD5\u5C06\u4F1A\u76F4\u63A5\u4F7F\u7528\u8FD9\u4E2A\u65B0\u521B\u5EFA\u7684\u7528\u6237\u3002</p><p>\u5BF9\u4E8E On-the-fly\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u6240\u6709\u7528\u5230\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u90FD\u5728\u6D4B\u8BD5\u7528\u4F8B\u5F00\u59CB\u524D\u5B9E\u65F6\u51C6\u5907\u3002<strong>\u91C7\u7528 On-the-fly \u65B9\u5F0F\u521B\u5EFA\u7684\u6570\u636E\uFF0C\u90FD\u662F\u7531\u6D4B\u8BD5\u7528\u4F8B\u81EA\u5DF1\u7EF4\u62A4\u7684\uFF0C\u4E0D\u4F1A\u4F9D\u8D56\u4E8E\u6D4B\u8BD5\u7528\u4F8B\u5916\u7684\u4EFB\u4F55\u6570\u636E\uFF0C\u4ECE\u800C\u4FDD\u8BC1\u4E86\u6570\u636E\u7684\u51C6\u786E\u6027\u548C\u53EF\u63A7\u6027\uFF0C\u6700\u5927\u7A0B\u5EA6\u5730\u907F\u514D\u4E86\u51FA\u73B0\u201C\u810F\u201D\u6570\u636E\u7684\u53EF\u80FD</strong>\u3002</p><p>\u90A3\u5230\u5E95\u4EC0\u4E48\u662F\u201C\u810F\u201D\u6570\u636E\u5462\uFF1F\u8FD9\u91CC\u7684\u201C\u810F\u201D\u6570\u636E\u662F\u6307\uFF0C\u6570\u636E\u5728\u88AB\u5B9E\u9645\u4F7F\u7528\u524D\uFF0C\u5DF2\u7ECF\u88AB\u8FDB\u884C\u4E86\u975E\u9884\u671F\u7684\u4FEE\u6539\u3002</p><p>\u4ECE\u7406\u8BBA\u4E0A\u6765\u8BB2\uFF0C\u8FD9\u79CD\u7531\u81EA\u5DF1\u521B\u5EFA\u548C\u7EF4\u62A4\u6570\u636E\u7684\u65B9\u5F0F\uFF0C\u662F\u6700\u4F73\u7684\u5904\u7406\u65B9\u5F0F\uFF0C\u5F88\u591A\u65E9\u671F\u7684\u6D4B\u8BD5\u8D44\u6599\u90FD\u63A8\u8350\u91C7\u7528\u8FD9\u79CD\u65B9\u5F0F\u3002\u4F46\u662F\uFF0C\u968F\u7740\u8F6F\u4EF6\u67B6\u6784\u7684\u53D1\u5C55\uFF0C\u4EE5\u53CA\u8F6F\u4EF6\u53D1\u5E03\u9891\u7387\u7684\u5FEB\u901F\u589E\u957F\uFF0C\u8FD9\u79CD\u65B9\u5F0F\u7684\u5F0A\u7AEF\u8D8A\u6765\u8D8A\u660E\u663E\uFF0C\u4E3B\u8981\u4F53\u73B0\u5728\u4EE5\u4E0B\u4E09\u65B9\u9762\uFF1A</p><p><strong>\u9996\u5148\uFF0C\u5B9E\u65F6\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u6BD4\u8F83\u8017\u65F6</strong>\u3002\u5728\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7684\u8FC7\u7A0B\u4E2D\u5B9E\u65F6\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u5C06\u76F4\u63A5\u5BFC\u81F4\u6D4B\u8BD5\u7528\u4F8B\u7684\u6574\u4F53\u6267\u884C\u65F6\u95F4\u53D8\u957F\u3002</p><p>\u6211\u66FE\u7EDF\u8BA1\u8FC7\u4E00\u4E2A\u5927\u578B\u7535\u5546\u7F51\u7AD9\u7684\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u65F6\u95F4\uFF0C\u603B\u7684\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u65F6\u95F4\u4E2D\uFF0C\u6709 30%-40%\u7684\u65F6\u95F4\u82B1\u5728\u4E86\u6D4B\u8BD5\u6570\u636E\u7684\u5B9E\u65F6\u51C6\u5907\u4E0A\uFF0C\u4E5F\u5C31\u662F\u8BF4\u6D4B\u8BD5\u6570\u636E\u7684\u5B9E\u65F6\u51C6\u5907\u82B1\u8D39\u4E86\u5DEE\u4E0D\u591A\u4E00\u534A\u7684\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u65F6\u95F4\u3002</p><p>\u5BF9\u4F20\u7EDF\u8F6F\u4EF6\u4F01\u4E1A\u6765\u8BF4\uFF0C\u5B83\u4EEC\u53EF\u80FD\u5E76\u4E0D\u592A\u5728\u610F\u8FD9\u591A\u51FA\u6765\u7684\u6D4B\u8BD5\u6267\u884C\u65F6\u95F4\uFF0C\u56E0\u4E3A\u5B83\u4EEC\u7684\u8F6F\u4EF6\u53D1\u5E03\u5468\u671F\u6BD4\u8F83\u957F\uFF0C\u7559\u7ED9\u6D4B\u8BD5\u7684\u65F6\u95F4\u4E5F\u6BD4\u8F83\u957F\uFF0C\u6240\u4EE5\u8FD9\u591A\u51FA\u6765\u7684\u65F6\u95F4\u53EF\u4EE5\u5FFD\u7565\u4E0D\u8BA1\u3002</p><p>\u4F46\u662F\uFF0C\u5BF9\u4E8E\u4E92\u8054\u7F51\u8F6F\u4EF6\u4F01\u4E1A\u6765\u8BF4\uFF0C\u5B83\u4EEC\u7684\u8F6F\u4EF6\u53D1\u5E03\u9891\u7387\u5F88\u9AD8\uFF0C\u76F8\u5E94\u5730\u7559\u7ED9\u6D4B\u8BD5\u6267\u884C\u7684\u65F6\u95F4\u4E5F\u90FD\u5F88\u77ED\uFF0C\u90A3\u4E48\u7F29\u77ED\u6D4B\u8BD5\u6570\u636E\u7684\u51C6\u5907\u65F6\u95F4\u7684\u91CD\u8981\u6027\u5C31\u4E0D\u8A00\u800C\u55BB\u4E86\u3002</p><p>\u8981\u89E3\u51B3\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u8017\u65F6\u7684\u95EE\u9898\uFF0C\u9664\u4E86\u4ECE\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u51FD\u6570\u7684\u5B9E\u73B0\u5165\u624B\u5916\uFF0C\u8FD8\u53EF\u4EE5\u8003\u8651\u91C7\u7528\u6211\u540E\u9762\u8981\u4ECB\u7ECD\u7684\u4E8B\u5148\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E Out-of-box \u7684\u65B9\u5F0F\u3002</p><p><strong>\u5176\u6B21\uFF0C\u6D4B\u8BD5\u6570\u636E\u672C\u8EAB\u5B58\u5728\u590D\u6742\u7684\u5173\u8054\u6027</strong>\u3002\u5F88\u591A\u65F6\u5019\u4F60\u4E3A\u4E86\u521B\u5EFA\u4E00\u4E2A\u4F60\u9700\u8981\u4F7F\u7528\u7684\u4E1A\u52A1\u6570\u636E\uFF0C\u5F80\u5F80\u9700\u8981\u5148\u521B\u5EFA\u4E00\u5806\u5176\u4ED6\u76F8\u5173\u8054\u7684\u6570\u636E\uFF0C\u8D8A\u662F\u4E1A\u52A1\u94FE\u540E\u671F\u7684\u6570\u636E\uFF0C\u8FD9\u4E2A\u95EE\u9898\u5C31\u8D8A\u4E25\u91CD\u3002</p><p>\u6BD4\u5982\uFF0C\u521B\u5EFA\u8BA2\u5355\u6570\u636E\u8FD9\u4E2A\u6700\u5178\u578B\u7684\u6848\u4F8B\u3002\u7531\u4E8E\u521B\u5EFA\u8BA2\u5355\u7684\u6570\u636E\u51C6\u5907\u51FD\u6570\u9700\u8981\u63D0\u4F9B\u8BF8\u5982\u5356\u5BB6\u3001\u4E70\u5BB6\u3001\u5546\u54C1 ID \u7B49\u4E00\u7CFB\u5217\u7684\u524D\u7F6E\u6570\u636E\uFF0C\u6240\u4EE5\u4F60\u5C31\u4E0D\u5F97\u4E0D\u5148\u521B\u5EFA\u51FA\u8FD9\u4E9B\u524D\u7F6E\u6570\u636E\u3002\u8FD9\u6837\u505A\uFF0C\u4E00\u65B9\u9762\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u7684\u590D\u6742\u6027\u76F4\u7EBF\u4E0A\u5347\uFF0C\u53E6\u4E00\u65B9\u9762\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u6240\u9700\u8981\u7684\u65F6\u95F4\u4E5F\u4F1A\u53D8\u5F97\u66F4\u957F\u3002</p><p>\u4E3A\u4E86\u7F13\u89E3\u8FD9\u4E2A\u95EE\u9898\uFF0C\u4F60\u53EF\u4EE5\u8003\u8651\u5C06\u90E8\u5206\u76F8\u5BF9\u7A33\u5B9A\u7684\u6570\u636E\u4E8B\u5148\u521B\u5EFA\u597D\uFF0C\u800C\u4E0D\u8981\u91C7\u7528 On-the-fly \u7684\u65B9\u5F0F\u53BB\u521B\u5EFA\u6240\u6709\u7684\u6570\u636E\u3002</p><p><strong>\u6700\u540E\u4E00\u4E2A\u95EE\u9898\u6765\u81EA\u4E8E\u5FAE\u670D\u52A1\u67B6\u6784\u7684\u8C03\u6574</strong>\u3002\u65E9\u671F\u7684\u8F6F\u4EF6\u67B6\u6784\u90FD\u662F\u5355\u4F53\u7684\uFF0C\u53EA\u8981\u6D4B\u8BD5\u73AF\u5883\u90E8\u7F72\u6210\u529F\u4E86\uFF0C\u90A3\u4E48\u6240\u6709\u7684\u529F\u80FD\u5C31\u90FD\u53EF\u4EE5\u4F7F\u7528\u4E86\u3002\u800C\u73B0\u5982\u4ECA\uFF0C\u5927\u91CF\u7684\u4E92\u8054\u7F51\u4EA7\u54C1\u90FD\u91C7\u7528\u4E86\u5FAE\u670D\u52A1\u67B6\u6784\uFF0C\u6240\u4EE5\uFF0C\u5F88\u591A\u65F6\u5019\u6D4B\u8BD5\u73AF\u5883\u5E76\u4E0D\u662F 100%\u5904\u4E8E\u5168\u90E8\u53EF\u7528\u7684\u72B6\u6001\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u5E76\u4E0D\u662F\u6240\u6709\u7684\u670D\u52A1\u90FD\u662F\u53EF\u7528\u7684\uFF0C\u8FD9\u5C31\u7ED9\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u5E26\u6765\u4E86\u65B0\u7684\u6311\u6218\u3002</p><p>\u6BD4\u5982\uFF0C\u4F60\u4E3A\u4E86\u6D4B\u8BD5\u7528\u6237\u767B\u5F55\u529F\u80FD\uFF0C\u6839\u636E On-the-fly \u7684\u7B56\u7565\uFF0C\u4F60\u9996\u5148\u9700\u8981\u521B\u5EFA\u4E00\u4E2A\u65B0\u7528\u6237\u3002\u5047\u8BBE\u5728\u5FAE\u670D\u52A1\u67B6\u6784\u4E0B\uFF0C\u6CE8\u518C\u7528\u6237\u548C\u7528\u6237\u767B\u5F55\u96B6\u5C5E\u4E8E\u4E24\u4E2A\u4E0D\u540C\u7684\u5FAE\u670D\u52A1\uFF0C\u800C\u6B64\u65F6\u6CE8\u518C\u7528\u6237\u7684\u5FAE\u670D\u52A1\u6070\u597D\u56E0\u4E3A\u67D0\u79CD\u539F\u56E0\u5904\u4E8E\u4E0D\u53EF\u7528\u72B6\u6001\uFF0C\u90A3\u4E48\u8FD9\u65F6\u4F60\u5C31\u65E0\u6CD5\u6210\u529F\u521B\u5EFA\u8FD9\u4E2A\u7528\u6237\uFF0C\u4E5F\u5C31\u662F\u65E0\u6CD5\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u3002\u56E0\u6B64\uFF0C\u6574\u4E2A\u6D4B\u8BD5\u7528\u4F8B\u90FD\u65E0\u6CD5\u987A\u5229\u6267\u884C\uFF0C\u663E\u7136\u8FD9\u4E0D\u662F\u6211\u4EEC\u60F3\u8981\u7684\u7ED3\u679C\u3002</p><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E2A\u95EE\u9898\uFF0C\u4F60\u53EF\u4EE5\u91C7\u7528\u4E8B\u5148\u521B\u5EFA\u6570\u636E Out-of-box \u7684\u65B9\u5F0F\uFF0C\u53EA\u8981\u80FD\u591F\u4FDD\u8BC1\u6D4B\u8BD5\u73AF\u5883\u5728\u67D0\u4E2A\u65F6\u95F4\u6BB5\u6CA1\u6709\u95EE\u9898\uFF0C\u90A3\u4E48\u5C31\u53EF\u4EE5\u5728\u8FD9\u4E2A\u65F6\u95F4\u6BB5\u4E8B\u5148\u521B\u5EFA\u597D\u6D4B\u8BD5\u6570\u636E\u3002</p><p>\u4E3A\u4E86\u89E3\u51B3\u4E0A\u8FF0\u4E09\u4E2A\u95EE\u9898\uFF0COut-of-box\uFF08\u5373\u4E8B\u5148\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF09\u7684\u65B9\u5F0F\u5C31\u5E94\u8FD0\u800C\u751F\u4E86\u3002\u90A3\u4E48\uFF0C</p><p>\u63A5\u4E0B\u6765\u6211\u4EEC\u5C31\u4E00\u8D77\u770B\u770B\u8FD9\u4E2A\u65B9\u5F0F\u7684\u539F\u7406\uFF0C\u4EE5\u53CA\u9002\u7528\u7684\u573A\u666F\u5427\u3002</p><p><strong>Out-of-box</strong></p><p>Out-of-box \u65B9\u6CD5\uFF0C\u53C8\u79F0\u5F00\u7BB1\u5373\u7528\u65B9\u6CD5\uFF0C\u6307\u7684\u662F\u5728\u51C6\u5907\u6D4B\u8BD5\u73AF\u5883\u65F6\u5C31\u9884\u5148\u5C06\u6D4B\u8BD5\u9700\u8981\u7528\u5230\u7684\u6570\u636E\u5168\u90E8\u51C6\u5907\u597D\uFF0C\u800C\u4E0D\u662F\u5728\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u5B9E\u65F6\u521B\u5EFA\u3002\u56E0\u6B64\uFF0C\u6211\u4EEC\u53EF\u4EE5\u8282\u7701\u4E0D\u5C11\u6D4B\u8BD5\u7528\u4F8B\u7684\u6267\u884C\u65F6\u95F4\uFF0C\u540C\u65F6\u4E5F\u4E0D\u4F1A\u5B58\u5728\u7531\u4E8E\u73AF\u5883\u95EE\u9898\u65E0\u6CD5\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\u800C\u963B\u788D\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7684\u60C5\u51B5\u3002\u4E5F\u5C31\u662F\u8BF4 Out-of-box \u65B9\u6CD5\u53EF\u4EE5\u514B\u670D On-the-fly \u65B9\u6CD5\u7684\u7F3A\u70B9\uFF0C\u90A3\u4E48\u8FD9\u4E2A\u65B9\u5F0F\u53C8\u4F1A\u5F15\u5165\u54EA\u4E9B\u81F4\u547D\u7684\u65B0\u95EE\u9898\u5462\uFF1F</p><p><strong>Out-of-box \u6700\u81F4\u547D\u7684\u95EE\u9898\u662F\u201C\u810F\u201D\u6570\u636E\u3002</strong></p><p>\u6BD4\u5982\uFF0C\u6211\u4EEC\u5728\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u4F7F\u7528\u4E8B\u5148\u521B\u5EFA\u597D\u7684\u7528\u6237\u8FDB\u884C\u767B\u5F55\u6D4B\u8BD5\uFF0C\u4F46\u8FD9\u4E2A\u7528\u6237\u7684\u5BC6\u7801\u88AB\u5176\u4ED6\u4EBA\u65E0\u610F\u4E2D\u4FEE\u6539\u4E86\uFF0C\u5BFC\u81F4\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u65F6\u767B\u5F55\u5931\u8D25\uFF0C\u4E5F\u5C31\u4E0D\u80FD\u987A\u5229\u5B8C\u6210\u6D4B\u8BD5\u4E86\u3002\u90A3\u4E48\uFF0C\u6B64\u65F6\u8FD9\u4E2A\u6D4B\u8BD5\u7528\u6237\u6570\u636E\u5C31\u6210\u4E3A\u4E86\u201C\u810F\u201D\u6570\u636E\u3002</p><p>\u518D\u6BD4\u5982\uFF0C\u6211\u4EEC\u5728\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u4F7F\u7528\u4E8B\u5148\u521B\u5EFA\u7684\u6D4B\u8BD5\u4F18\u60E0\u5238\u53BB\u5B8C\u6210\u8BA2\u5355\u64CD\u4F5C\uFF0C\u4F46\u662F\u7531\u4E8E\u67D0\u79CD\u539F\u56E0\u8FD9\u5F20\u4F18\u60E0\u5238\u5DF2\u7ECF\u88AB\u4F7F\u7528\u8FC7\u4E86\uFF0C\u5BFC\u81F4\u8BA2\u5355\u64CD\u4F5C\u7684\u5931\u8D25\uFF0C\u4E5F\u5C31\u610F\u5473\u7740\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u5931\u8D25\u3002\u90A3\u4E48\uFF0C\u6B64\u65F6\u8FD9\u4E2A\u6D4B\u8BD5\u4F18\u60E0\u5238\u6570\u636E\u4E5F\u662F\u201C\u810F\u201D\u6570\u636E\u3002</p><p>\u7531\u6B64\u53EF\u89C1\uFF0C\u8FD9\u4E9B\u4E8B\u5148\u521B\u5EFA\u597D\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u5728\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7684\u90A3\u4E2A\u65F6\u523B\uFF0C\u662F\u5426\u4F9D\u7136\u53EF\u7528\u5176\u5B9E\u662F\u4E0D\u4E00\u5B9A\u7684\uFF0C\u56E0\u4E3A\u8FD9\u4E9B\u6570\u636E\u5F88\u6709\u53EF\u80FD\u5728\u88AB\u4F7F\u7528\u524D\u5DF2\u7ECF\u53D1\u751F\u4E86\u975E\u9884\u671F\u7684\u4FEE\u6539\u3002</p><p>\u8FD9\u4E9B\u975E\u9884\u671F\u7684\u4FEE\u6539\u4E3B\u8981\u6765\u81EA\u4E8E\u4EE5\u4E0B\u4E09\u4E2A\u65B9\u9762\uFF1A</p><ol><li>\u5176\u4ED6\u6D4B\u8BD5\u7528\u4F8B\u4F7F\u7528\u4E86\u8FD9\u4E9B\u4E8B\u5148\u521B\u5EFA\u597D\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u5E76\u4FEE\u6539\u4E86\u8FD9\u4E9B\u6570\u636E\u7684\u72B6\u6001\uFF1B</li><li>\u6267\u884C\u624B\u5DE5\u6D4B\u8BD5\u65F6\uFF0C\u56E0\u4E3A\u76F4\u63A5\u4F7F\u7528\u4E86\u4E8B\u5148\u521B\u5EFA\u597D\u7684\u6570\u636E\uFF0C\u5F88\u6709\u53EF\u80FD\u5C31\u4F1A\u4FEE\u6539\u4E86\u67D0\u4E9B\u6D4B\u8BD5\u6570\u636E\uFF1B</li><li>\u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\u7684\u8C03\u8BD5\u8FC7\u7A0B\uFF0C\u4FEE\u6539\u4E86\u4E8B\u5148\u521B\u5EFA\u7684\u6D4B\u8BD5\u6570\u636E\uFF1B</li></ol><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E9B\u201C\u810F\u201D\u6570\u636E\uFF0C\u6211\u4EEC\u53EA\u80FD\u901A\u8FC7\u4F18\u5316\u6D41\u7A0B\u53BB\u63A7\u5236\u6570\u636E\u7684\u4F7F\u7528\u3002\u76EE\u524D\uFF0C\u4E1A\u5185\u6709\u4E9B\u516C\u53F8\u4F1A\u5C06\u6240\u6709\u4E8B\u5148\u521B\u5EFA\u597D\u7684\u6D4B\u8BD5\u6570\u636E\u5217\u5728\u4E00\u4E2A Wiki \u9875\u9762\uFF0C\u7136\u540E\u6309\u7167\u4E0D\u540C\u7684\u6D4B\u8BD5\u6570\u636E\u533A\u6BB5\u6765\u5206\u914D\u4F7F\u7528\u5BF9\u8C61\u3002</p><p>\u6BD4\u5982\uFF0C\u5047\u8BBE\u6211\u4EEC\u4E8B\u5148\u521B\u5EFA\u4E86 1000 \u4E2A\u6D4B\u8BD5\u7528\u6237\uFF0C\u90A3\u4E48\u7528\u6237 ID \u5728 0001-0200 \u8303\u56F4\u5185\u6570\u636E\u7ED9\u8FD9\u4E2A\u56E2\u961F\u4F7F\u7528\uFF0C\u800C\u7528\u6237 ID \u5728 0201-0500 \u8303\u56F4\u5185\u7684\u6570\u636E\u5219\u7ED9\u53E6\u4E00\u4E2A\u56E2\u961F\u4F7F\u7528\u3002\u8FD9\u4E2A\u5206\u914D\u5DE5\u4F5C\uFF0C\u8981\u9760\u6D41\u7A0B\u4FDD\u8BC1\uFF0C\u90A3\u4E48\u524D\u63D0\u5C31\u662F\u6240\u6709\u4EBA\u90FD\u8981\u9075\u5B88\u8FD9\u4E9B\u6D41\u7A0B\u3002</p><p>\u4F46\u6211\u4E00\u76F4\u8BA4\u4E3A\uFF0C\u4F46\u51E1\u9700\u8981\u9760\u6D41\u7A0B\u4FDD\u8BC1\u7684\u4E00\u5B9A\u4E0D\u662F\u6700\u9760\u8C31\u7684\uFF0C\u56E0\u4E3A\u4F60\u65E0\u6CD5\u786E\u4FDD\u6240\u6709\u4EBA\u90FD\u4F1A\u9075\u5B88\u6D41\u7A0B\u3002\u4E5F\u6B63\u662F\u56E0\u4E3A\u8FD9\u4E2A\u539F\u56E0\uFF0C\u5728\u5B9E\u9645\u9879\u76EE\u4E2D\u6211\u4EEC\u8FD8\u662F\u4F1A\u7ECF\u5E38\u770B\u5230\u7531\u201C\u810F\u201D\u6570\u636E\u5F15\u53D1\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u5931\u8D25\u7684\u6848\u4F8B\u3002</p><p>\u66F4\u7CDF\u7CD5\u7684\u662F\uFF0C\u5982\u679C\u81EA\u52A8\u5316\u6D4B\u8BD5\u7528\u4F8B\u76F4\u63A5\u91C7\u7528\u786C\u7F16\u7801\u7684\u65B9\u5F0F\uFF0C\u53BB\u8C03\u7528\u90A3\u4E9B\u53EA\u80FD\u88AB\u4E00\u6B21\u6027\u4F7F\u7528\u7684\u6D4B\u8BD5\u6570\u636E\uFF08\u6BD4\u5982\u8BA2\u5355\u6570\u636E\u3001\u4F18\u60E0\u5238\u7B49\uFF09\u7684\u8BDD\uFF0C\u4F60\u4F1A\u53D1\u73B0\u6D4B\u8BD5\u7528\u4F8B\u53EA\u80FD\u5728\u7B2C\u4E00\u6B21\u6267\u884C\u65F6\u901A\u8FC7\uFF0C\u540E\u9762\u518D\u6267\u884C\u90FD\u4F1A\u56E0\u4E3A\u6D4B\u8BD5\u6570\u636E\u7684\u95EE\u9898\u800C\u5931\u8D25\u3002</p><p>\u6240\u4EE5\uFF0C\u4F60\u8FD8\u9700\u8981\u5728\u6D4B\u8BD5\u7528\u4F8B\u7EA7\u522B\u4FDD\u8BC1\u6D4B\u8BD5\u6570\u636E\u53EA\u88AB\u8C03\u7528\u4E00\u6B21\uFF0C\u800C\u8FD9\u5F80\u5F80\u4F1A\u6D89\u53CA\u5230\u8DE8\u6D4B\u8BD5\u7528\u4F8B\u7684\u6D4B\u8BD5\u6570\u636E\u7EF4\u62A4\u95EE\u9898\uFF0C\u5F80\u5F80\u5B9E\u73B0\u8D77\u6765\u975E\u5E38\u9EBB\u70E6\u3002\u6240\u4EE5\u8BF4\uFF0COut-of-box \u65B9\u6CD5\u4E0D\u9002\u7528\u4E8E\u53EA\u80FD\u4E00\u6B21\u6027\u4F7F\u7528\u7684\u6D4B\u8BD5\u6570\u636E\u573A\u666F\u3002</p><p><strong>\u7EFC\u5408\u8FD0\u7528 On-the-fly \u548C Out-of-box</strong></p><p>\u4E3A\u4E86\u5145\u5206\u5229\u7528 On-the-fly \u548C Out-of-box \u8FD9\u4E24\u79CD\u65B9\u5F0F\u7684\u5404\u81EA\u4F18\u70B9\uFF0C\u5E76\u4E14\u89C4\u907F\u5404\u81EA\u7684\u7F3A\u70B9\uFF0C\u5B9E\u9645\u7684\u5DE5\u7A0B\u5B9E\u8DF5\u4E2D\uFF0C\u5F80\u5F80\u662F\u91C7\u7528\u7EFC\u5408\u8FD0\u7528 On-the-fly \u548C Out-of-box \u7684\u65B9\u5F0F\u6765\u5B9E\u73B0\u6D4B\u8BD5\u6570\u636E\u7684\u51C6\u5907\u7684\u3002</p><p><strong>\u5728\u5B9E\u9645\u7684\u6D4B\u8BD5\u9879\u76EE\u4E2D\uFF0C\u6211\u4EEC\u53EF\u4EE5\u6839\u636E\u6D4B\u8BD5\u6570\u636E\u7684\u7279\u6027\uFF0C\u628A\u5B83\u4EEC\u5206\u4E3A\u4E24\u5927\u7C7B\uFF0C\u7528\u4E1A\u5185\u7684\u884C\u8BDD\u6765\u8BB2\u5C31\u662F\u201C\u6B7B\u6C34\u6570\u636E\u201D\u548C\u201C\u6D3B\u6C34\u6570\u636E\u201D\u3002</strong></p><p>\u201C\u6B7B\u6C34\u6570\u636E\u201D\u662F\u6307\u90A3\u4E9B\u76F8\u5BF9\u7A33\u5B9A\uFF0C\u4E0D\u4F1A\u5728\u4F7F\u7528\u8FC7\u7A0B\u4E2D\u6539\u53D8\u72B6\u6001\uFF0C\u5E76\u4E14\u53EF\u4EE5\u88AB\u591A\u6B21\u4F7F\u7528\u7684\u6570\u636E\u3002\u6BD4\u5982\uFF0C\u5546\u54C1\u5206\u7C7B\u3001\u5546\u54C1\u54C1\u724C\u3001\u573A\u9986\u4FE1\u606F\u7B49\u3002\u8FD9\u7C7B\u6570\u636E\u5C31\u975E\u5E38\u9002\u5408\u91C7\u7528 Out-of-box \u65B9\u5F0F\u6765\u521B\u5EFA\u3002</p><p><strong>\u8FD9\u91CC\u9700\u8981\u7279\u522B\u8BF4\u660E\u7684\u662F\uFF0C\u54EA\u4E9B\u6570\u636E\u5C5E\u4E8E\u201C\u6B7B\u6C34\u6570\u636E\u201D\u5E76\u4E0D\u662F\u7EDD\u5BF9\u7684\uFF0C\u7531\u6D4B\u8BD5\u76EE\u7684\u51B3\u5B9A\u3002</strong></p><p>\u6BD4\u5982\uFF0C\u7528\u6237\u6570\u636E\u5728\u5927\u591A\u6570\u7684\u975E\u7528\u6237\u76F8\u5173\u7684\u6D4B\u8BD5\u7528\u4F8B\u4E2D\u57FA\u672C\u5C5E\u4E8E\u201C\u6B7B\u6C34\u6570\u636E\u201D\uFF0C\u56E0\u4E3A\u7EDD\u5927\u591A\u6570\u7684\u4E1A\u52A1\u6D4B\u8BD5\u90FD\u4F1A\u5305\u542B\u7528\u6237\u767B\u5F55\u7684\u64CD\u4F5C\uFF0C\u800C\u4E14\u5E76\u4E0D\u4F1A\u53BB\u4FEE\u6539\u7528\u6237\u672C\u8EAB\u7684\u6570\u636E\u5C5E\u6027\uFF0C\u6240\u4EE5\u8FD9\u65F6\u6211\u4EEC\u5C31\u53EF\u4EE5\u5C06\u7528\u6237\u6570\u636E\u6309\u7167\u201C\u6B7B\u6C34\u6570\u636E\u201D\u5904\u7406\uFF0C\u4E5F\u5C31\u662F\u91C7\u7528 Out-of-box \u7684\u65B9\u5F0F\u521B\u5EFA\u3002</p><p>\u4F46\u662F\uFF0C\u5BF9\u4E8E\u90A3\u4E9B\u4E13\u95E8\u6D4B\u8BD5\u7528\u6237\u8D26\u53F7\u7684\u6D4B\u8BD5\u7528\u4F8B\u6765\u8BB2\uFF0C\u5F80\u5F80\u4F1A\u6D89\u53CA\u5230\u7528\u6237\u64A4\u9500\u3001\u6FC0\u6D3B\u3001\u4FEE\u6539\u5BC6\u7801\u7B49\u64CD\u4F5C\uFF0C\u90A3\u4E48\u6B64\u65F6\u7684\u7528\u6237\u6570\u636E\u5C31\u4E0D\u518D\u662F\u201C\u6B7B\u6C34\u6570\u636E\u201D\u4E86\uFF0C\u800C\u5E94\u8BE5\u6309\u7167\u201C\u6D3B\u6C34\u6570\u636E\u201D\u5904\u7406\u3002</p><p>\u201C\u6D3B\u6C34\u6570\u636E\u201D\u662F\u6307\u90A3\u4E9B\u53EA\u80FD\u88AB\u4E00\u6B21\u6027\u4F7F\u7528\uFF0C\u6216\u8005\u7ECF\u5E38\u4F1A\u88AB\u4FEE\u6539\u7684\u6D4B\u8BD5\u6570\u636E\u3002\u6700\u5178\u578B\u7684\u6570\u636E\u662F\u4F18\u60E0\u5238\u3001\u5546\u54C1\u672C\u8EAB\u3001\u8BA2\u5355\u7B49\u7C7B\u4F3C\u7684\u6570\u636E\u3002\u8FD9\u7C7B\u6570\u636E\u901A\u5E38\u5728\u88AB\u4E00\u6B21\u6027\u4F7F\u7528\u540E\u72B6\u6001\u5C31\u53D1\u751F\u4E86\u53D8\u5316\uFF0C\u4E0D\u80FD\u53CD\u590D\u4F7F\u7528\u3002\u90A3\u4E48\u8FD9\u7C7B\u6D4B\u8BD5\u6570\u636E\uFF0C\u5C31\u66F4\u9002\u5408\u91C7\u7528 On-the-fly \u81EA\u7EF4\u62A4\u7684\u65B9\u5F0F\u3002</p><p>\u540C\u65F6\uFF0C\u7531\u4E8E\u6709 Out-of-box \u6570\u636E\u7684\u652F\u6301\uFF0C\u8FD9\u7C7B\u6570\u636E\u5F80\u5F80\u4E0D\u9700\u8981\u4ECE\u6700\u6E90\u5934\u5F00\u59CB\u521B\u5EFA\uFF0C\u800C\u662F\u53EF\u4EE5\u57FA\u4E8E\u5DF2\u6709\u7684 Out-of-box \u6570\u636E\u751F\u6210\u3002</p><p>\u6BD4\u5982\uFF0C\u5728\u4F7F\u7528 On-the-fly \u65B9\u5F0F\u521B\u5EFA\u8BA2\u5355\u6570\u636E\u65F6\uFF0C\u4F60\u53EF\u4EE5\u76F4\u63A5\u4F7F\u7528 Out-of-box \u7684\u7528\u6237\u6570\u636E\u6765\u4F5C\u4E3A\u4E70\u5BB6\u6570\u636E\u3002</p><p>\u7531\u6B64\u53EF\u89C1\uFF0C\u7EFC\u5408\u8FD0\u7528\u8FD9\u4E24\u7C7B\u65B9\u6CD5\uFF0C\u53EF\u4EE5\u4EE5\u4E92\u8865\u7684\u65B9\u5F0F\u89E3\u51B3\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u7684\u5F88\u591A\u75DB\u70B9\uFF0C\u6BD4\u5982\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u6BD4\u8F83\u8017\u65F6\u3001\u6D4B\u8BD5\u6570\u636E\u5B58\u5728\u201C\u810F\u201D\u6570\u636E\u7684\u53EF\u80FD\uFF0C\u4EE5\u53CA\u6D4B\u8BD5\u73AF\u5883\u4E0D\u7A33\u5B9A\u9020\u6210\u7684\u6D4B\u8BD5\u6570\u636E\u65E0\u6CD5\u521B\u5EFA\u7B49\u95EE\u9898\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u4ECA\u5929\u6211\u4ECE\u6D4B\u8BD5\u6570\u636E\u521B\u5EFA\u65F6\u673A\u7684\u89D2\u5EA6\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86 On-the-fly \u548C Out-of-box \u8FD9\u4E24\u7C7B\u521B\u5EFA\u6570\u636E\u7684\u65B9\u5F0F\u3002</p><p>On-the-fly \u65B9\u6CD5\u53C8\u79F0\u4E3A\u5B9E\u65F6\u521B\u5EFA\u65B9\u6CD5\uFF0C\u6307\u7684\u662F\u5728\u6D4B\u8BD5\u7528\u4F8B\u7684\u4EE3\u7801\u4E2D\u5B9E\u65F6\u521B\u5EFA\u6D4B\u8BD5\u7528\u4F8B\u6240\u8981\u4F7F\u7528\u5230\u7684\u6D4B\u8BD5\u6570\u636E\uFF0C\u5177\u6709\u6570\u636E\u53EF\u9760\u6027\u9AD8\u7684\u4F18\u70B9\uFF0C\u4F46\u662F\u4F1A\u6BD4\u8F83\u8017\u65F6\u3002</p><p>\u800C Out-of-box \u65B9\u6CD5\u53C8\u79F0\u4E3A\u5F00\u7BB1\u5373\u7528\u65B9\u6CD5\uFF0C\u6307\u7684\u662F\u5728\u51C6\u5907\u6D4B\u8BD5\u73AF\u5883\u65F6\u5C31\u4E8B\u5148\u51C6\u5907\u597D\u6D4B\u8BD5\u9700\u8981\u7528\u5230\u7684\u5168\u90E8\u6570\u636E\u3002\u8FD9\u6837\u53EF\u4EE5\u6709\u6548\u7F29\u77ED\u6D4B\u8BD5\u7528\u4F8B\u7684\u6267\u884C\u65F6\u95F4\uFF0C\u4F46\u662F\u5B58\u5728\u201C\u810F\u201D\u6570\u636E\u7684\u95EE\u9898\u3002</p><p>\u6700\u540E\uFF0C\u6211\u4ECE\u201C\u6B7B\u6C34\u6570\u636E\u201D\u548C\u201C\u6D3B\u6C34\u6570\u636E\u201D\u7684\u89D2\u5EA6\u8BA8\u8BBA\u4E86\u5982\u4F55\u7EFC\u5408\u8FD0\u7528\u4E0A\u8FF0\u4E24\u79CD\u65B9\u5F0F\u521B\u5EFA\u6D4B\u8BD5\u6570\u636E\uFF0C\u5176\u4E2D\u201C\u6B7B\u6C34\u6570\u636E\u201D\u9002\u5408\u7528 Out-of-box \u7684\u65B9\u5F0F\uFF0C\u800C\u201C\u6D3B\u6C34\u6570\u636E\u201D\u9002\u5408\u91C7\u7528 On-the-fly \u7684\u65B9\u5F0F\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u4F60\u6240\u5728\u7684\u9879\u76EE\u4E2D\uFF0C\u91C7\u7528\u7684\u662F\u4EC0\u4E48\u6837\u7684\u6D4B\u8BD5\u6570\u636E\u51C6\u5907\u7B56\u7565\uFF0C\u8FD9\u4E2A\u7B56\u7565\u7684\u4F18\u7F3A\u70B9\u662F\u4EC0\u4E48\uFF1F\u4E3A\u4EC0\u4E48\u4F1A\u9009\u62E9\u8FD9\u6837\u7684\u7B56\u7565\u5462\uFF1F\u53E6\u5916\uFF0C\u4F60\u6240\u5728\u56E2\u961F\u4F1A\u4F7F\u7528\u7EBF\u4E0A\u771F\u5B9E\u7684\u6570\u636E\u8FDB\u884C\u6D4B\u8BD5\u5417\uFF1F</p>',57);function f(r,e){return n}var O=p(o,[["render",f],["__file","36.html.vue"]]);export{O as default};
